sql:
SELECT AVG(fitness) AS average_fitness
FROM feasible_individuals
WHERE experiment_id = 1;

SELECT experiment_id, AVG(average_fitness) AS average_fitness
FROM optimization_results
GROUP BY experiment_id;

SELECT experiment_id
FROM optimization_results
WHERE feasible_individuals = (SELECT MAX(feasible_individuals) FROM optimization_results);

SELECT MAX(fitness)
FROM feasible_individuals
WHERE experiment_id = 0;

SELECT experiment_id, AVG(average_fitness) AS overall_average_fitness
FROM optimization_results
GROUP BY experiment_id;

SELECT experiment_id, average_fitness
FROM optimization_results
WHERE experiment_id = 1;

SELECT phenotype, fitness
FROM fittest_individuals
WHERE experiment_id = 0 AND generation_id = 1;

SELECT experiment_id, COUNT(component_id) AS component_count
     FROM connected_components
     GROUP BY experiment_id;

SELECT SUM(duration) AS total_duration
FROM experiment_generations
WHERE experiment_id = 1;

SELECT generation_id, COUNT(individual_id) AS feasible_count
FROM feasible_individuals
GROUP BY generation_id;

SELECT experiment_id
FROM optimization_results
WHERE average_fitness = (SELECT MAX(average_fitness) FROM optimization_results);
